// src/components/TrustIndicators.jsx
const TrustIndicators = () => (
    <section className="py-20 bg-gradient-to-br from-gray-900 to-purple-900">
      <div className="max-w-4xl mx-auto px-4 text-center">
        <h2 className="text-3xl font-bold text-white mb-12">
          Trusted by Security Experts Worldwide
        </h2>
        <div className="grid grid-cols-2 md:grid-cols-4 gap-8">
          {['99.7%', '10M+', '0.2s', '100+'].map((item, i) => (
            <div key={i} className="text-center">
              <p className="text-4xl font-bold text-white mb-2">{item}</p>
              <p className="text-gray-400 text-sm uppercase tracking-wider">
                {['Accuracy', 'Analyses', 'Detection Speed', 'Supported Formats'][i]}
              </p>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
